+        Transaction::begin(self, cx).await
+    }
+
+    /// Open a dedicated Pub/Sub connection.
+    pub async fn pubsub(&self, cx: &Cx) -> Result<RedisPubSub, RedisError> {
+        RedisPubSub::connect(cx, self.config.clone()).await
+    }
